import{z as l,b as e,c as t,i as o}from"./index-dc5fff9e.js";const c={class:"markdown-body"},s=o("<h2>项目履历</h2><h4>项目1 - 设备更新换代</h4><ul><li>描 述： 为了缩小硬件体积和成本，将约30c*10cm的H桥控制电路PCB集成到控制电路PCB，将开发芯片从STM32更换到ESP32，增加蓝牙和WiFi功能。</li><li>负责内容：对以前旧的代码经行重构，使用VSCode和IDF插件构建基于ESP32的项目代码。协同对硬件的EMC测试。</li><li>详细说明： <ul><li>理清杂糅的代码结构，使用分层结构，将代码分层为驱动层，组件层，用户层。</li><li>将粗放的H桥控制方式（输出为0或100%），更改为使用PID调节。</li><li>将简易的数码管逻辑控制代码重新设计，</li></ul></li></ul><h2>获奖项目</h2><h4>大学期间</h4><ul><li>2016年04月 “全志杯”微创客高校挑战赛 一等奖(10000元)</li><li>2015年12月 全球创客马拉松-深圳站 二等奖(3000元)</li><li>2015年09月 全国大学生电子设计竞赛广东赛区 三等奖</li><li>2014年12月 广东省大学生电子设计竞赛 二等奖</li><li>获得奖学金5次（一等奖，二等奖，三等奖），优秀学生2次，优秀学生干部1次，优秀干事1次</li></ul>",6),n=[s],d={},m="",p=l({__name:"blog",setup(r,{expose:i}){return i({frontmatter:{},excerpt:void 0}),(a,_)=>(e(),t("div",c,n))}});export{p as default,m as excerpt,d as frontmatter};
